package com.example.ppm.controller;import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;import com.example.ppm.common.*;import com.example.ppm.entity.User;import com.example.ppm.mapper.UserMapper;import com.example.ppm.security.CurrentUserContext;import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;import org.springframework.web.bind.annotation.*;import java.util.*;
@RestController @RequestMapping("/api/admin/users") public class AdminController{private final UserMapper m;private final BCryptPasswordEncoder e;public AdminController(UserMapper m,BCryptPasswordEncoder e){this.m=m;this.e=e;}private void admin(){if(!"ADMIN".equals(CurrentUserContext.require().role()))throw new BusinessException(403,"无权限");}private User one(Long id){User u=m.selectById(id);if(u==null)throw new BusinessException(404,"用户不存在");return u;}private void guardLast(User u,String role){if("ADMIN".equals(u.getRole())&&!"ADMIN".equals(role)&&m.selectCount(new LambdaQueryWrapper<User>().eq(User::getRole,"ADMIN"))<=1)throw new BusinessException(400,"不能操作最后一个管理员");}
@GetMapping public R<List<User>>list(@RequestParam(required=false)String keyword){admin();List<User> users=m.selectList(new LambdaQueryWrapper<User>().like(keyword!=null&&!keyword.isBlank(),User::getUsername,keyword).orderByDesc(User::getId));users.forEach(u->u.setPasswordHash(null));return R.ok(users);}@PutMapping("/{id}/status")public R<Void>status(@PathVariable Long id,@RequestBody Map<String,String>x){admin();User u=one(id);guardLast(u,"DISABLED".equals(x.get("status"))?"USER":u.getRole());u.setStatus(x.get("status"));m.updateById(u);return R.ok();}@PutMapping("/{id}/role")public R<Void>role(@PathVariable Long id,@RequestBody Map<String,String>x){admin();User u=one(id);guardLast(u,x.get("role"));u.setRole(x.get("role"));m.updateById(u);return R.ok();}@PutMapping("/{id}/password")public R<Void>pw(@PathVariable Long id,@RequestBody Map<String,String>x){admin();User u=one(id);String p=x.get("newPassword");if(p==null||p.length()<6)throw new BusinessException(400,"密码至少6位");u.setPasswordHash(e.encode(p));m.updateById(u);return R.ok();}@DeleteMapping("/{id}")public R<Void>del(@PathVariable Long id){admin();User u=one(id);if(u.getId().equals(CurrentUserContext.require().userId()))throw new BusinessException(400,"不能删除自己");guardLast(u,"USER");m.deleteById(id);return R.ok();}}
